import React from 'react';
import propTypes from 'prop-types';
import me from '../static assets/me.jpg';

class About extends React.Component {
    render() {
        return (
            <div id="about-page">
                <header id="about-title-card">
                <div id="about-back">
                        <button type="button" id="main-1" className="back" onClick={this.props.handleClick}><i className="fas fa-angle-left"></i> Menu</button>
                    </div>
                    <h1 id="about-title">About Me</h1>
                </header>
                <div id="about-main-card">
                    <div id="about-text">
                        <section>
                        <h2>Front End Developer | Writer | Doer</h2>
                        <p>Welcome to my page! My name is Austin, and I like learning. I like learning so much, in fact, that I am like a gentle river, flowing from ecosystem to ecosystem and carrying new knowledge along with me...but also like GODZILLA, bombarding new skills and using my learning-claws to dismantle them and become their ruler! Ahem. Suffice it to say, I am a jack of all trades (and don't let the adage fool you, I am a master of them too!). If you've made it this far, it's likely you want to know more about my experience in one of said trades. So to help you in your quest, I will grant you what you seek; here is the no-frills, all-facts rundown of Austin Knauer. I am a:</p>
                                <ul>
                                    <li>Three-time certified front end warrior with a thorough, constantly-expanding knowledge of the most modern front end technologies. My experience covres HTML, CSS, JavaScript including ES6, React including React Hooks, Redux, Bootstrap, jQuery, SASS, REST APIs, Wordpress, Webpack, Babel, Git, and Node. I am a flexible front end programmer who can make your web development dreams come true.</li>
                                    <li>Skilled communicator and published writer with a creative writing centered Bachelor's degree. I am a language chameleon, perfectly shaping my communication and content writing to fit the goals, style, and voice of any project or brand.</li>
                                    <li>An insatiably curious and indefatigable worker who brings passion to everything I do. I tackle any and every challenge and always come out on top. I am the worker and collaborator you can depend on to always reeturn stellar results.</li>
                                </ul>
                        </section>
                        <figure id="about-img">
                        <img src={me} id="pic" alt="Austin Knauer">
                        </img>
                        <figcaption><em>Hey it's me!</em></figcaption>
                    </figure>
                        <section>
                        <h2>Fast Facts:</h2>
                        
                        <ul>
                                    <li>I have certifications in Responsive Web Design, JavaScript Algorithms and Data Structures, and Front End Libraries.</li>
                                    <li>I have a BA in Liberal Arts with minors in English and History from Colorado State University, where I was nominated as a University Honors Scholar.</li>
                                    <li>My web development work is carefully attentive to both responsive design principles and accessibility.</li>
                                </ul>
                    
                        </section>
                        
                        <section>
                        <h2>Got your attention?</h2>
                        <p>Check out some of my work on the Portfolio page. Or, if you want a more detailed breakdown of my experience, download my Resume. If you think we'd be a good fit, you can find a way to reach me on the Contact page.</p>
                        </section>
                       
                    </div>
                    
                    
                </div>



            </div>
        )
    }
}

About.propTypes = {handleClick: propTypes.func.isRequired};

export default About;
